// Limpia y normaliza los datos del Excel
const items = $input.all();

return items.map((item, index) => {
  const data = item.json;

  // Extrae cédula (ajusta el nombre de columna según tu Excel)
  const cedula = String(data['Cédula'] || data['CÉDULA'] || data['CEDULA'] || data['Cedula'] || '').trim();

  // Si no hay cédula válida, skip
  if (!cedula || cedula.length < 10) {
    return null;
  }

  return {
    json: {
      cedula: cedula,
      nombre: String(data['Nombre Completo'] || data['Nombre'] || data['NOMBRE'] || '').trim(),
      escuela: String(data['Escuela'] || data['ESCUELA'] || '').trim(),
      nivel: String(data['Nivel Actual'] || data['Nivel'] || data['NIVEL'] || '').trim(),
      email: String(data['Email UIDE'] || data['Email'] || data['EMAIL'] || '').trim(),
      edad: parseInt(data['Edad'] || data['EDAD'] || 0) || null
    }
  };
}).filter(item => item !== null); // Remueve nulls
